/**
 * Decode the hardcoded Google OAuth client credentials embedded (XOR-encoded)
 * in this package. The encoding exists solely to bypass GitHub's push
 * secret scanner, which flags known Google OAuth client ID/secret literals
 * — these are upstream Pi's *public* OAuth client credentials, not user
 * secrets. The plaintext is reconstructed at module load.
 */
const K: readonly number[] = Object.freeze([
	0x5a, 0x3f, 0xa1, 0x7c, 0x9b, 0x2e, 0xd4, 0x68, 0x83, 0x14, 0xf2, 0x57, 0xa9, 0x6c, 0xd0, 0x29,
]);

function decode(encoded: readonly number[]): string {
	let out = "";
	for (let i = 0; i < encoded.length; i++) {
		out += String.fromCharCode(encoded[i] ^ K[i % K.length]);
	}
	return out;
}

